// server/index.js
import express from "express";
import cors from "cors";
import multer from "multer";
import path from "path";
import { fileURLToPath } from "url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const app = express();
app.use(cors());
app.use(express.json({ limit: "5mb" }));

// static uploads
const upload = multer({ dest: path.join(__dirname, "uploads") });
app.use("/uploads", express.static(path.join(__dirname, "uploads")));

let POSTS = []; // [{id, text, city, media:[{url,type}], hashtags:[], createdAt, ...}]
let REPLIES = {}; // id -> [{...}]

// List with cursor (timestamp cursor)
app.get("/api/community", (req, res) => {
  const { city="", tab="for you", limit="20", cursor } = req.query;
  const L = Math.min(100, Math.max(1, parseInt(limit,10) || 20));
  let items = [...POSTS];

  if (city) items = items.filter(p => (p.city||"").toLowerCase().includes(String(city).toLowerCase()));
  // naive ranking for "for you"
  if (tab === "for you") items.sort((a,b)=>(b.likes+(b.reposts||0)*2)-(a.likes+(a.reposts||0)*2)||b.createdAt-a.createdAt);
  else items.sort((a,b)=>b.createdAt-a.createdAt);

  const after = cursor ? Number(cursor) : Infinity;
  items = items.filter(p => p.createdAt < after);
  const page = items.slice(0, L);
  const nextCursor = page.length === L ? String(page[page.length-1].createdAt) : null;

  res.json({ items: page, nextCursor });
});

app.post("/api/community", (req, res) => {
  const { text, city, media=[], quoteOf=null, hashtags=[] } = req.body || {};
  const post = {
    id: crypto.randomUUID(),
    author: { name: "You", handle: "you", avatar: "" },
    city, text, media, quoteOf, hashtags,
    createdAt: Date.now(), likes: 0, reposts: 0, replies: [],
    youLiked: false, youReposted: false,
  };
  POSTS.unshift(post);
  res.json(post);
});

app.post("/api/community/:id/like", (req, res) => {
  const p = POSTS.find(x=>x.id===req.params.id);
  if (p) { p.likes = (p.likes||0)+1; p.youLiked=true; }
  res.json({ ok:true });
});

app.post("/api/community/:id/repost", (req, res) => {
  const p = POSTS.find(x=>x.id===req.params.id);
  if (p) { p.reposts = (p.reposts||0)+1; p.youReposted=true; }
  res.json({ ok:true });
});

app.post("/api/community/:id/reply", (req, res) => {
  const p = POSTS.find(x=>x.id===req.params.id);
  if (!p) return res.status(404).json({error:"not found"});
  const r = { id: crypto.randomUUID(), author:{name:"You",handle:"you",avatar:""}, text:req.body.text, createdAt: Date.now(), likes:0 };
  p.replies.push(r);
  res.json(r);
});

// Media upload
app.post("/api/upload", upload.single("file"), (req,res)=>{
  const url = `/uploads/${req.file.filename}`;
  res.json({ url });
});

const PORT = process.env.PORT || 4000;
app.listen(PORT, ()=> console.log("API up on", PORT));
